#include <stdio.h>
int main() {
    int n;
    scanf("%d", &n);
    int a[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &a[i]);
    }
    int sum = 0;
    for (int i = 1; i < n; i++) {
        sum += abs(a[i] - a[i - 1]);
    }
    int sum2 = 0;
    for (int i = 1; i < n - 1; i++) {
        sum2 += abs(a[i] - a[0]) + abs(a[i] - a[n - 1]);
    }
    if (sum == sum2) {
        printf("YES\n");
    } else {
        printf("NO\n");
    }
    return 0;
}

