const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let n;
let a;
readline.on('line', line => {
    if (i == 0) {
        n = parseInt(line);
    } else {
        a = line.split(' ').map(num => parseInt(num));
        let sum = 0;
        for (let j = 1; j < n; j++) {
            sum += Math.abs(a[j] - a[j - 1]);
        }
        let sum2 = 0;
        for (let j = 1; j < n - 1; j++) {
            sum2 += Math.abs(a[j] - a[0]) + Math.abs(a[j] - a[n - 1]);
        }
        console.log(sum == sum2 ? 'YES' : 'NO');
        readline.close();
    }
    i++;
});
